<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  :root {
    --bg: #f1f3f7;
    --col-bg: #e9ecf2;
    --card-bg: #ffffff;
    --ink: #1f2430;
    --muted: #6b7280;
    --accent: #4f6ef7;
    --radius: 12px;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: var(--bg);
    color: var(--ink);
    min-height: 100vh;
    padding: 24px;
  }
  h1 {
    margin: 0 0 20px;
    font-size: 22px;
    font-weight: 700;
    letter-spacing: -0.01em;
  }
  .toolbar {
    display: flex;
    gap: 8px;
    margin-bottom: 24px;
    max-width: 520px;
  }
  #new-card {
    flex: 1;
    padding: 10px 14px;
    font-size: 14px;
    border: 1px solid #d4d8e0;
    border-radius: 8px;
    background: #fff;
    outline: none;
  }
  #new-card:focus {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(79, 110, 247, 0.15);
  }
  #add-card {
    padding: 10px 18px;
    font-size: 14px;
    font-weight: 600;
    color: #fff;
    background: var(--accent);
    border: none;
    border-radius: 8px;
    cursor: pointer;
  }
  #add-card:hover { background: #3d5ce5; }
  #add-card:active { transform: translateY(1px); }

  .board {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 16px;
    align-items: start;
    max-width: 1100px;
  }
  .column {
    background: var(--col-bg);
    border-radius: var(--radius);
    padding: 12px;
    min-height: 220px;
    transition: background 0.15s, outline 0.15s;
    outline: 2px dashed transparent;
    outline-offset: -2px;
  }
  .column.drag-over {
    background: #dde3ef;
    outline-color: var(--accent);
  }
  .column-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 4px 6px 12px;
  }
  .column-header h2 {
    margin: 0;
    font-size: 13px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    color: var(--muted);
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; }
  #col-todo .dot { background: #f59e0b; }
  #col-doing .dot { background: #4f6ef7; }
  #col-done .dot { background: #10b981; }
  .count {
    font-size: 12px;
    font-weight: 600;
    color: var(--muted);
    background: #fff;
    border-radius: 999px;
    min-width: 24px;
    height: 24px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0 8px;
    box-shadow: 0 1px 2px rgba(0,0,0,0.06);
  }
  .cards {
    display: flex;
    flex-direction: column;
    gap: 8px;
    min-height: 60px;
  }
  .card {
    background: var(--card-bg);
    border-radius: 10px;
    padding: 12px 14px;
    box-shadow: 0 1px 3px rgba(20, 24, 40, 0.10), 0 1px 2px rgba(20, 24, 40, 0.06);
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    font-size: 14px;
    line-height: 1.4;
    border: 1px solid rgba(0,0,0,0.04);
  }
  .card:hover { box-shadow: 0 3px 8px rgba(20, 24, 40, 0.14); }
  .card.dragging { opacity: 0.45; }
  .card-title { word-break: break-word; }
  .card-del {
    flex: none;
    border: none;
    background: transparent;
    color: #b0b6c3;
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    padding: 2px 4px;
    border-radius: 6px;
  }
  .card-del:hover { color: #e0455a; background: #fdeef0; }

  @media (max-width: 720px) {
    .board { grid-template-columns: 1fr; }
  }
</style>
</head>
<body>
  <h1>Kanban Board</h1>

  <div class="toolbar">
    <input id="new-card" type="text" placeholder="New card title…">
    <button id="add-card">Add card</button>
  </div>

  <div class="board">
    <section class="column" id="col-todo">
      <div class="column-header">
        <h2><span class="dot"></span>To Do</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-doing">
      <div class="column-header">
        <h2><span class="dot"></span>Doing</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-done">
      <div class="column-header">
        <h2><span class="dot"></span>Done</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
  </div>

<script>
(function () {
  var STORAGE_KEY = 'kanban-board-state';
  var COLUMN_IDS = ['col-todo', 'col-doing', 'col-done'];
  var nextId = 1;

  var input = document.getElementById('new-card');
  var addBtn = document.getElementById('add-card');

  function saveState() {
    var state = [];
    COLUMN_IDS.forEach(function (colId) {
      var cards = document.querySelectorAll('#' + colId + ' .card');
      cards.forEach(function (card) {
        state.push({
          id: card.dataset.id,
          title: card.querySelector('.card-title').textContent,
          column: colId
        });
      });
    });
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* storage unavailable */ }
  }

  function updateCounts() {
    COLUMN_IDS.forEach(function (colId) {
      var col = document.getElementById(colId);
      col.querySelector('.count').textContent =
        col.querySelectorAll('.card').length;
    });
  }

  function makeCard(id, title) {
    var card = document.createElement('div');
    card.className = 'card';
    card.dataset.id = id;
    card.setAttribute('draggable', 'true');

    var span = document.createElement('span');
    span.className = 'card-title';
    span.textContent = title;

    var del = document.createElement('button');
    del.className = 'card-del';
    del.type = 'button';
    del.textContent = '✕';
    del.setAttribute('aria-label', 'Delete card');
    del.addEventListener('click', function () {
      card.remove();
      updateCounts();
      saveState();
    });

    card.appendChild(span);
    card.appendChild(del);

    card.addEventListener('dragstart', function (e) {
      e.dataTransfer.setData('text/plain', id);
      e.dataTransfer.effectAllowed = 'move';
      card.classList.add('dragging');
    });
    card.addEventListener('dragend', function () {
      card.classList.remove('dragging');
    });

    return card;
  }

  function addCard(title, colId, id) {
    var cardId = id || ('card-' + (nextId++));
    var num = parseInt(String(cardId).replace('card-', ''), 10);
    if (!isNaN(num) && num >= nextId) nextId = num + 1;
    var card = makeCard(cardId, title);
    document.querySelector('#' + colId + ' .cards').appendChild(card);
    updateCounts();
    saveState();
    return card;
  }

  // Column drag targets
  COLUMN_IDS.forEach(function (colId) {
    var col = document.getElementById(colId);

    col.addEventListener('dragover', function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      col.classList.add('drag-over');
    });
    col.addEventListener('dragleave', function (e) {
      if (!col.contains(e.relatedTarget)) col.classList.remove('drag-over');
    });
    col.addEventListener('drop', function (e) {
      e.preventDefault();
      col.classList.remove('drag-over');
      var id = e.dataTransfer.getData('text/plain');
      var card = document.querySelector('.card[data-id="' + id + '"]');
      if (card) {
        col.querySelector('.cards').appendChild(card);
        updateCounts();
        saveState();
      }
    });
  });

  // Add-card controls
  function handleAdd() {
    var title = input.value.trim();
    if (!title) return;
    addCard(title, 'col-todo');
    input.value = '';
    input.focus();
  }
  addBtn.addEventListener('click', handleAdd);
  input.addEventListener('keydown', function (e) {
    if (e.key === 'Enter') handleAdd();
  });

  // Restore persisted state
  function loadState() {
    var raw = null;
    try {
      raw = localStorage.getItem(STORAGE_KEY);
    } catch (e) { /* storage unavailable */ }
    if (!raw) { updateCounts(); return; }
    var state;
    try {
      state = JSON.parse(raw);
    } catch (e) { updateCounts(); return; }
    if (!Array.isArray(state)) { updateCounts(); return; }
    state.forEach(function (item) {
      if (item && item.title && COLUMN_IDS.indexOf(item.column) !== -1) {
        addCard(item.title, item.column, item.id);
      }
    });
    updateCounts();
  }

  loadState();
})();
</script>
</body>
</html>
